package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatIsNullStringSetTest {

    @Test
    void testIsNullStringSet_whenNullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set private final field nullString to null
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, null);

        assertFalse(format.isNullStringSet());
    }

    @Test
    void testIsNullStringSet_whenNullStringIsNonNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        // Using reflection to set private final field nullString to a non-null value
        Field nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        nullStringField.set(format, "NULL");

        assertTrue(format.isNullStringSet());
    }
}
